          rows: [["Medicare", "All eligible beneficiaries at 65", "Primary insurer at 65+", "Part B: $202.90/mo, Deductible: $283"], ["TRICARE", "Active duty, retirees, families", "Secondary after 65 (primary before)", "Varies by TRICARE plan type"], ["VA Benefits", "Service-connected conditions", "Primary for VA-covered services", "No copay for service-connected care"], ["Supplemental/Medigap", "Gaps in Medicare coverage", "After Medicare pays", "Varies by plan, typically $100-300/mo"]],
